expected_output:
{
  "goal": "Write a release checklist for version 1.2.0",
  "summary": "A 10-step plan to produce a comprehensive, actionable release checklist for version 1.2.0 covering scope confirmation, quality gates, documentation, deployment safety (backup/rollback), stakeholder communication, and post-release monitoring.",
  "steps": [
    {
      "index": 1,
      "title": "Confirm scope and freeze the 1.2.0 change set",
      "rationale": "A checklist is only meaningful if the contents of the release are pinned. Ties back to the assumption that features/fixes/enhancements for 1.2.0 are clearly understood.",
      "actions": [
        "Gather the list of merged PRs, issues, and tickets targeting the 1.2.0 milestone.",
        "Cross-reference the CHANGELOG.md [Unreleased] section and promote entries under a new [1.2.0] heading draft.",
        "Declare a code freeze date and record the freeze commit SHA on the release branch."
      ]
    },
    {
      "index": 2,
      "title": "Enumerate components requiring verification",
      "rationale": "Directly addresses the first consideration — every shippable component must appear on the checklist so nothing is silently untested.",
      "actions": [
        "List affected packages/modules, public APIs, CLI surfaces, MCP surfaces, and external integrations.",
        "Tag each component with an owner and a required verification level (smoke / full regression).",
        "Flag components whose behaviour changed vs. 1.1.x for extra scrutiny."
      ]
    },
    {
      "index": 3,
      "title": "Define the test matrix (unit, integration, UAT)",
      "rationale": "Addresses the testing-procedures consideration by making required gates explicit and measurable.",
      "actions": [
        "Require green unit tests with coverage threshold check.",
        "Require integration tests against staging with representative fixtures.",
        "Schedule a UAT window with product/QA sign-off criteria and a defect severity rubric."
      ]
    },
    {
      "index": 4,
      "title": "Run release-critical quality gates",
      "rationale": "Locks down non-functional risks (lint, typing, security, layering) before shipping.",
      "actions": [
        "Execute lint, type-check, and import-linter layer checks.",
        "Run secret-scan and dependency vulnerability audit.",
        "Perform performance/smoke benchmarks against agreed thresholds."
      ]
    },
    {
      "index": 5,
      "title": "Update documentation and release notes",
      "rationale": "Covers the documentation consideration — user manuals, API docs, and upgrade notes must match shipped behaviour.",
      "actions": [
        "Finalise CHANGELOG.md 1.2.0 section with dates, highlights, and breaking changes.",
        "Regenerate API reference and update user-facing manuals for new/changed features.",
        "Draft release notes and an upgrade/migration guide for end-users."
      ]
    },
    {
      "index": 6,
      "title": "Prepare backup and rollback plans",
      "rationale": "Addresses the backup and rollback considerations — deployment safety net.",
      "actions": [
        "Snapshot production database and configuration prior to deploy; verify snapshot restore on staging.",
        "Document the exact rollback command/runbook (previous image tag, DB migration down-step, feature flags).",
        "Define rollback decision criteria (error rate, p95 latency, critical bug severity)."
      ]
    },
    {
      "index": 7,
      "title": "Version, tag, and build release artifacts",
      "rationale": "Turns the frozen code set into immutable, deployable artifacts.",
      "actions": [
        "Bump version to 1.2.0 in package metadata and commit on the release branch.",
        "Create annotated git tag v1.2.0 and publish build artifacts (wheel/sdist/container image) to the registry.",
        "Record artifact digests/checksums in the release notes."
      ]
    },
    {
      "index": 8,
      "title": "Plan and execute deployment",
      "rationale": "Converts a release into an operational event with a clear sequence and owners.",
      "actions": [
        "Schedule the deploy window and notify on-call/stakeholders.",
        "Deploy to staging → canary → full production with validation checkpoints between stages.",
        "Run post-deploy smoke tests and compare against pre-release health baselines."
      ]
    },
    {
      "index": 9,
      "title": "Communicate release to stakeholders and users",
      "rationale": "Addresses the communication-strategy consideration so internal and external audiences get the right message at the right time.",
      "actions": [
        "Send internal announcement (engineering, support, product) with highlights and known issues.",
        "Publish external changelog/blog post/email for end-users.",
        "Brief customer support on expected questions and the triage/escalation path."
      ]
    },
    {
      "index": 10,
      "title": "Post-release monitoring and sign-off",
      "rationale": "Addresses post-release monitoring and support — closes the loop from ship to stability.",
      "actions": [
        "Watch dashboards (error rate, latency, saturation) and logs for an agreed post-release window.",
        "Open a triage channel for incoming bug reports and prioritise critical-severity fixes for a 1.2.1 patch if needed.",
        "Run a release retrospective and mark the checklist signed-off once exit criteria are met."
      ]
    }
  ]
}
